```json
{
  "medio": {...},
  "shareUrls": {
    "facebook": "https://...",
    "instagram": "https://...",
    "twitter": "https://...",
    "linkedin": "https://..."
  },
  "shareContent": {
    "title": "...",
    "description": "...",
    "hashtags": ["#WebFestival", "#Fotografía"]
